#!/usr/bin/perl
use strict;
use warnings;
use File::Basename;
use POSIX qw(strftime);

# Check command line arguments
if (@ARGV < 1) {
    die "Usage: $0 <filename_or_directory> [--compress] [--checksum] [--list] [--restore <archive>]\n";
}

my $filename = $ARGV[0];
my $compress_flag = grep { $_ eq '--compress' } @ARGV;
my $checksum_flag = grep { $_ eq '--checksum' } @ARGV;
my $list_flag = grep { $_ eq '--list' } @ARGV;
