if ($list_flag) {
    print "[INFO] Listing contents of archive: $filename\n";
    if ($filename =~ /\.tar\.gz$/ || $filename =~ /\.tgz$/) {
        my $output = `tar -tzf "$filename" 2>&1`;
        my $exit_code = $? >> 8;
        if ($exit_code != 0) {
            die "[ERROR] Failed to list archive contents:\n$output\n";
