    }
    unless ($restore_archive && -e $restore_archive) {
        die "[ERROR] Please provide a valid archive file after --restore.\n";
    }

    my $restore_dir = "restored_${timestamp}";
    mkdir $restore_dir or die "[ERROR] Failed to create restore directory: $!\n";

